// Lấy JWT token từ header Authorization
const headers = $input.first().json.headers || {};
const authHeader = headers.authorization || headers.Authorization || '';
if (!authHeader.startsWith('Bearer ')) {
  return [{ json: { _valid: false, _code: 401, error: 'Thiếu Authorization: Bearer <token>' } }];
}
const token = authHeader.replace('Bearer ', '').trim();
if (token.length < 50) {
  return [{ json: { _valid: false, _code: 401, error: 'Token không hợp lệ' } }];
}
try {
  const parts = token.split('.');
  if (parts.length !== 3) throw new Error('Token format sai');
  const payload = JSON.parse(Buffer.from(parts[1], 'base64url').toString());
  if (payload.exp && payload.exp < Math.floor(Date.now() / 1000)) {
    return [{ json: { _valid: false, _code: 401, error: 'Token đã hết hạn' } }];
  }
  return [{ json: { _valid: true, _token: token, _body: $input.first().json.body || $input.first().json } }];
} catch (e) {
  return [{ json: { _valid: false, _code: 401, error: 'Token decode lỗi: ' + e.message } }];
}

// Kiểm tra quyền (S2-6) + dựng dòng ghi Sheet theo TIÊU ĐỀ TIẾNG VIỆT (S1-1).
// S1-B FIX (2026-06-21): biến H_BASE chứa tiêu đề "chuẩn" của hệ thống. Nếu Sheet
//   của bạn dùng VIẾT HOA/THƯỜNG khác H_BASE → Google Sheets sẽ tạo CỘT RÁC mới.
//   Hãy kiểm tra tab "6.Timeline VMP" và đồng nhất tiêu đề với H_BASE bên dưới
//   (case-sensitive). Đặc biệt: "Thẩm", "Deadline VMP" phải KHỚP CHỮ HOA.
const row0 = $input.first().json || {};
const uid = row0.uid, email = row0.email, role = row0.role;
const extract = $('1. Extract JWT').first().json;
if (!uid || !email) return [{ json: { _ok:false, _code:401, error:'Token không hợp lệ hoặc hết hạn — Supabase từ chối' } }];
if (role === 'viewer' || role === '') return [{ json: { _ok:false, _code:403, error:'Tài khoản không có quyền ghi (viewer hoặc chưa cấp quyền)' } }];
const body = extract._body;
if (body.action !== 'updateRow') return [{ json: { _ok:true, _skip:true, ok:true, msg:'Bỏ qua (không phải updateRow)' } }];
if (!body.id) return [{ json: { _ok:false, _code:400, error:'Thiếu mã thẩm định (id)' } }];
if (!body.patch || typeof body.patch !== 'object') return [{ json: { _ok:false, _code:400, error:'Thiếu patch' } }];

const allowed = ['ngay_de_cuong','tt_de_cuong','lich_td','ngay_tham_dinh','tt_tham_dinh','ngay_bao_cao','tt_bao_cao','ngay_vmp','tt_vmp'];
const bad = Object.keys(body.patch).filter(k => !allowed.includes(k));
if (bad.length) return [{ json: { _ok:false, _code:400, error:'Trường không được phép: ' + bad.join(', ') } }];

// QUAN TRỌNG: H_BASE phải TRÙNG TUYỆT ĐỐI với tiêu đề trên Google Sheet (case-sensitive).
// Nếu Sheet thực tế khác viết hoa/thường → Google Sheets sẽ TẠO CỘT RÁC.
const H_BASE = {
  tt_de_cuong:    'Trạng thái đề cương',
  ngay_de_cuong:  'Thời gian thực tế hoàn thành đề cương',
  lich_td:        'Bộ phận quản lý xếp lịch thẩm định (dd/mm/yyyy hh:mm:ss)',
  tt_tham_dinh:   'Trạng thái thẩm định thực tế',
  ngay_tham_dinh: 'Thời gian thực tế hoàn thành Thẩm định thực tế',
  tt_bao_cao:     'Trạng thái báo cáo',
  ngay_bao_cao:   'Thời gian thực tế hoàn thành báo cáo',
  tt_vmp:         'Trạng thái VMP',
  ngay_vmp:       'Thời gian thực tế Deadline VMP',
};

const row = { 'ID thẩm định': String(body.id) };
for (const k of allowed) if (k in body.patch) row[H_BASE[k]] = (body.patch[k] == null ? '' : String(body.patch[k]));
return [{ json: { _ok:true, _user: email, _vc: String(body.id), _row: row } }];

// ====== SỬA 3 GIÁ TRỊ Ở ĐÂY (giữ nguyên ...$input để chuyển tiếp header/body) ======
return [{ json: { ...$input.first().json,
  GOOGLE_SHEET_ID: "1MPG6YbR6m-YrENqb8u7uS3O8RUYk7GCYuzQRbShtqP8",
  SUPABASE_URL: "https://ivembmikfhtyzhtqebgh.supabase.co",          // vd https://abcd.supabase.co  (KHÔNG có / ở cuối)
  SUPABASE_ANON_KEY: "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Iml2ZW1ibWlrZmh0eXpodHFlYmdoIiwicm9sZSI6ImFub24iLCJpYXQiOjE3ODIwODU0NzIsImV4cCI6MjA5NzY2MTQ3Mn0._IZwrZd9kaeP3HXhlE8Jl5VjNIP0O4C0k7GlnbDdfmg",
} }];

// Chuẩn hóa danh sách người nhận từ Sheet (tiêu đề tiếng Việt -> khóa ngắn).
// Sheet "CanhBao" có các cột (xem mẫu trong hướng dẫn):
//   Bật | Loại phạm vi | Phạm vi | Email nhận | Tên người nhận | Loại cảnh báo | Ngưỡng ngày
function norm(h){ return String(h==null?'':h).replace(/\s+/g,' ').trim().toLowerCase(); }
const MAP = {
  'bật':'enabled', 'bat':'enabled',
  'loại phạm vi':'scope_type', 'loai pham vi':'scope_type',
  'phạm vi':'scope', 'pham vi':'scope',
  'email nhận':'email', 'email nhan':'email', 'email':'email',
  'tên người nhận':'name', 'ten nguoi nhan':'name',
  'loại cảnh báo':'alert_kind', 'loai canh bao':'alert_kind',
  'ngưỡng ngày':'threshold_days', 'nguong ngay':'threshold_days',
};
const truthy = (v)=>{ const s=norm(v); return ['true','1','x','yes','co','có','bật','bat','on'].includes(s); };
const out=[];
for(const it of $input.all()){
  const raw=it.json||{}; const m={};
  for(const [k,v] of Object.entries(raw)){ const t=MAP[norm(k)]; if(t) m[t]=v; }
  if(!truthy(m.enabled)) continue;                 // chỉ lấy dòng đang bật
  const email=String(m.email||'').trim();
  if(!email || !email.includes('@')) continue;     // bỏ dòng thiếu email
  out.push({ json: {
    scope_type: norm(m.scope_type),                // 'tất cả' | 'bộ phận' | 'đối tượng'
    scope: String(m.scope||'').trim(),
    email, name: String(m.name||'').trim(),
    alert_kind: norm(m.alert_kind),                // 'quá hạn' | 'sắp đến hạn' | 'cả hai'
    threshold_days: m.threshold_days!=null && String(m.threshold_days).trim()!=='' ? parseInt(m.threshold_days,10) : null,
  }});
}
if(out.length===0) console.log('⚠ Không có dòng người nhận nào đang bật trong Sheet CanhBao.');
return out;

// rpc_due_alerts trả về 1 JSONB (mảng). Bung ra mỗi hạng mục = 1 item.
const row = $input.first().json;
let arr = row.due || row.rpc_due_alerts || [];
if (typeof arr === 'string') { try { arr = JSON.parse(arr); } catch { arr = []; } }
if (!Array.isArray(arr)) arr = [];
return arr.map(d => ({ json: d }));

// Ghép (người nhận x hạng mục đến hạn) -> danh sách email cần gửi.
// Lấy dữ liệu qua tham chiếu node (đảm bảo cả 2 nhánh đã chạy).
const recips = $('1b. Chuẩn hóa người nhận').all().map(i=>i.json);
const dues   = $('2b. Bung danh sách đến hạn').all().map(i=>i.json);
const soonDefault = Number($('CONFIG1').first().json.SOON_DAYS) || 7;
const n = (s)=>String(s==null?'':s).toLowerCase();
const out=[];
for (const d of dues) {
  for (const r of recips) {
    // 1) khớp phạm vi
    let scopeOK=false;
    if (r.scope_type.includes('tất') || n(r.scope)==='all') scopeOK=true;
    if (r.scope_type.includes('bộ'))  scopeOK = (n(r.scope)===n(d.department));
    if (r.scope_type.includes('đối')) scopeOK = (n(r.scope)===n(d.object_code) || n(r.scope)===n(d.validation_code));
    if (!scopeOK) continue;
    // 2) khớp loại cảnh báo
    const wantBoth = r.alert_kind.includes('cả') || r.alert_kind==='';
    const wantOver = r.alert_kind.includes('quá');
    const wantSoon = r.alert_kind.includes('sắp');
    if (!(wantBoth || (wantOver && d.alert_type==='overdue') || (wantSoon && d.alert_type==='due_soon'))) continue;
    // 3) ngưỡng ngày cho 'sắp đến hạn'
    if (d.alert_type==='due_soon') {
      const thr = (r.threshold_days!=null) ? r.threshold_days : soonDefault;
      if (Number(d.days_left) > thr) continue;
    }
    const key = `alert:${d.alert_type}:${d.validation_code}:${d.stage}:${d.due_date}:${r.email}`;
    out.push({ json: { ...d, _email: r.email, _name: r.name||'', _idem: key } });
  }
}
if(out.length===0) console.log('Không có cảnh báo nào cần gửi hôm nay.');
return out;

// Sau node Postgres, lấy lại dữ liệu hạng mục gốc của item hiện tại + cờ is_new.
const reg = $json.r || {};
const base = $('3. Ghép người nhận × hạng mục').item.json;
return [{ json: { ...base, is_new: !!reg.is_new } }];

// Dựng prompt cho Claude (có TRÍ NHỚ: lịch sử + cảnh báo cũ + xu hướng).
const ctx = $json.ctx || {};
const item = $('4b. Giữ dữ liệu + cờ mới').item.json;
const sys = "Bạn là trợ lý QA dược phẩm (GMP). Viết 2-3 câu tiếng Việt, ngắn gọn, lịch sự, "
  + "nhắc nhở phụ trách về hạng mục thẩm định sắp/đã đến hạn. Dựa vào LỊCH SỬ và XU HƯỚNG được cung cấp: "
  + "nếu hạng mục đã từng bị dời deadline hoặc đã từng quá hạn, hãy nêu rõ để nhấn mạnh mức ưu tiên. "
  + "Không bịa số liệu. Không thêm tiêu đề, chỉ trả về đoạn văn.";
const user = "DỮ LIỆU HẠNG MỤC:
" + JSON.stringify({
  ma: item.validation_code, doi_tuong: item.object_name, loai: item.validation_type,
  giai_doan: item.stage, han: item.due_date, con_lai_ngay: item.days_left,
  loai_canh_bao: item.alert_type, phu_trach: item.owner_name
}, null, 2) + "

BỐI CẢNH/BỘ NHỚ:
" + JSON.stringify({
  trang_thai_hien_tai: ctx.now, lich_su: ctx.history, canh_bao_truoc: ctx.past_alerts, xu_huong: ctx.trend
}, null, 2);
return [{ json: { ...item, _ai_system: sys, _ai_user: user,
  _ai_body: JSON.stringify({ model: "claude-sonnet-4-6", max_tokens: 400,
    system: sys, messages: [{ role: "user", content: user }] }) } }];

// Dựng email HTML. Ưu tiên đoạn văn AI; nếu AI lỗi/tắt -> nội dung mặc định.
const item = $('7. Dựng prompt AI').item.json;
let aiText = '';
try {
  const resp = $json;                 // output node Claude (nếu có)
  if (resp && resp.content && Array.isArray(resp.content)) {
    aiText = resp.content.filter(b=>b.type==='text').map(b=>b.text).join(' ').trim();
  }
} catch(e) {}
const over = item.alert_type === 'overdue';
const tone = over ? '#b00020' : '#9a6a00';
const label = over ? 'QUÁ HẠN' : 'SẮP ĐẾN HẠN';
const fallback = `Hạng mục ${item.validation_code} (${item.object_name||''}) — giai đoạn ${item.stage} ${over?'đã quá hạn':'sắp đến hạn'} `
  + `vào ${item.due_date}${over?'':` (còn ${item.days_left} ngày)`}. Đề nghị ${item.owner_name||'phụ trách'} kiểm tra và cập nhật tiến độ.`;
const body = aiText || fallback;
const subject = `[${label}] ${item.object_code} · ${item.stage} · ${item.due_date}`;
const html = `
<div style="font-family:Arial,sans-serif;max-width:600px;border:1px solid #eee;border-radius:10px;overflow:hidden">
  <div style="background:${tone};color:#fff;padding:12px 16px;font-weight:bold">VMP Monitor · Cảnh báo ${label}</div>
  <div style="padding:16px;color:#222;line-height:1.6">
    <p>${body}</p>
    <table style="border-collapse:collapse;font-size:13px;margin-top:8px">
      <tr><td style="padding:4px 10px;color:#666">Mã thẩm định</td><td style="padding:4px 10px"><b>${item.validation_code}</b></td></tr>
      <tr><td style="padding:4px 10px;color:#666">Đối tượng</td><td style="padding:4px 10px">${item.object_name||''} (${item.object_code})</td></tr>
      <tr><td style="padding:4px 10px;color:#666">Loại</td><td style="padding:4px 10px">${item.validation_type}</td></tr>
      <tr><td style="padding:4px 10px;color:#666">Giai đoạn</td><td style="padding:4px 10px">${item.stage}</td></tr>
      <tr><td style="padding:4px 10px;color:#666">Deadline</td><td style="padding:4px 10px"><b>${item.due_date}</b></td></tr>
      <tr><td style="padding:4px 10px;color:#666">Phụ trách</td><td style="padding:4px 10px">${item.owner_name||'—'}</td></tr>
    </table>
    <p style="font-size:11px;color:#999;margin-top:14px">Email tự động từ hệ thống VMP Monitor. Nội dung gợi ý do AI soạn — vui lòng kiểm tra trước khi hành động.</p>
  </div>
</div>`;
return [{ json: { ...item, _subject: subject, _html: html } }];

// ====== SỬA 2 GIÁ TRỊ Ở ĐÂY ======
// 1) ID của GOOGLE SHEET chứa DANH SÁCH NGƯỜI NHẬN cảnh báo (sheet bạn tự xây).
//    Lấy đoạn giữa /d/ và /edit trong URL.
// 2) Tên TAB chứa danh sách (mặc định "CanhBao").
// 3) SOON_DAYS: số ngày coi là "sắp đến hạn" mặc định (nếu dòng không ghi ngưỡng riêng).
return [{ json: { ...($input.first()?.json || {}),
  ALERT_SHEET_ID: "1MPG6YbR6m-YrENqb8u7uS3O8RUYk7GCYuzQRbShtqP8",
  ALERT_TAB: "CanhBao",
  SOON_DAYS: 7,
} }];

// Dựng dòng ghi Google Sheet theo TIÊU ĐỀ TIẾNG VIỆT, khớp 'ID thẩm định' (S1-1).
// S1-A FIX (2026-06-21): GIỮ pairedItem để node "4. Mark Done" / "5. Mark Error"
//   sau Google Sheets node lấy đúng `_outbox_id` từ "1. Claim Due Rows" tương ứng
//   với từng item (khi outbox đẩy >1 dòng cùng lúc).
const H = {
  tt_de_cuong:    'Trạng thái đề cương',
  ngay_de_cuong:  'Thời gian thực tế hoàn thành đề cương',
  lich_td:        'Bộ phận quản lý xếp lịch thẩm định (dd/mm/yyyy hh:mm:ss)',
  tt_tham_dinh:   'Trạng thái thẩm định thực tế',
  ngay_tham_dinh: 'Thời gian thực tế hoàn thành Thẩm định thực tế',
  tt_bao_cao:     'Trạng thái báo cáo',
  ngay_bao_cao:   'Thời gian thực tế hoàn thành báo cáo',
  tt_vmp:         'Trạng thái VMP',
  ngay_vmp:       'Thời gian thực tế Deadline VMP',
};
const ALLOWED = Object.keys(H);
const out = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const r = items[i].json;
  let patch = r.sheet_patch;
  if (typeof patch === 'string') { try { patch = JSON.parse(patch); } catch { patch = {}; } }
  if (!patch || typeof patch !== 'object') patch = {};
  const row = { 'ID thẩm định': String(r.validation_code) };
  for (const k of ALLOWED) if (k in patch) row[H[k]] = (patch[k] == null ? '' : String(patch[k]));
  // S1-A FIX: ĐẶT pairedItem RÕ RÀNG → Google Sheets node giữ được pairing
  // → $('1. Claim Due Rows').item.json._outbox_id ở các node sau sẽ TRỎ ĐÚNG item.
  out.push({ json: row, pairedItem: { item: i } });
}
return out;

// ====== SỬA 1 GIÁ TRỊ Ở ĐÂY ======
return [{ json: { ...($input.first()?.json || {}),
  GOOGLE_SHEET_ID: "1MPG6YbR6m-YrENqb8u7uS3O8RUYk7GCYuzQRbShtqP8",
} }];

// ============================================================
// DIFF ENGINE (S1-2 + S1-3) — so sánh Sheet vs Supabase theo validation_code
// ============================================================
const sheetRows = $('1. Read Sheet').all().map(i => i.json);
const dbRows = $('2. Read Supabase').all().map(i => i.json);
const s  = (v) => (v == null ? '' : String(v)).trim();
const lc = (v) => s(v).toLowerCase();
function toISO(v){ const t=s(v); if(!t) return null;
  let m=t.match(/^(\d{4})[-/](\d{1,2})[-/](\d{1,2})/);
  if(m) return `${m[1]}-${String(m[2]).padStart(2,'0')}-${String(m[3]).padStart(2,'0')}`;
  m=t.match(/^(\d{1,2})[-/](\d{1,2})[-/](\d{4})/);
  if(m) return `${m[3]}-${String(m[2]).padStart(2,'0')}-${String(m[1]).padStart(2,'0')}`;
  return null; }
function mapStatus(v){ const x=lc(v); if(!x) return 'not_started';
  const neg=/\b(chưa|chua|không|khong)\b/.test(x)||/not[_\s-]?started/.test(x);
  if(neg) return 'not_started';
  if(/hoàn thành|hoan thanh|done|đạt|dat|complete|completed|xong|✓/.test(x)) return 'completed';
  if(/đang|dang|progress|in[_\s-]?progress|thực hiện|thuc hien|wip/.test(x)) return 'in_progress';
  return 'not_started'; }
const numLoose=(v)=>{const n=parseFloat(String(v==null?'':v).replace(',','.')); return isFinite(n)?n:null;};
const intLoose=(v)=>{const n=parseInt(String(v==null?'':v).replace(/[^\d-]/g,''),10); return isFinite(n)?n:null;};

const sheetMap=new Map(); const sheetCodes=new Set(); const warnNonNum=[];
for(const r of sheetRows){
  const code=s(r.ma); if(!code) continue;
  if(/[a-zà-ỹ]/i.test(s(r.diem_trong_yeu))||/[a-zà-ỹ]/i.test(s(r.so_ngay_cong))) warnNonNum.push(s(r.id)||code); // S1-3: KHÔNG bỏ hàng
  const vc=s(r.id)||`${code}/${s(r.loai_td)||'PQ'}`;
  const rawSP=s(r.tt_de_cuong),rawSV=s(r.tt_tham_dinh),rawSR=s(r.tt_bao_cao),rawSVMP=s(r.tt_vmp);
  sheetCodes.add(code);
  sheetMap.set(vc,{validation_code:vc,object_code:code,
    validation_type:(s(r.loai_td)||'PQ').toUpperCase(),
    report_class:s(r.phan_loai_bc)||'Không phụ thuộc',
    owner_name:s(r.qa)||s(r.ns_khac)||'—',
    effort_days:numLoose(r.so_ngay_cong), criticality_score:intLoose(r.diem_trong_yeu),
    deadline_vmp:toISO(r.dl_vmp),deadline_protocol:toISO(r.dl_de_cuong),deadline_report:toISO(r.dl_bao_cao),
    actual_protocol_date:toISO(r.ngay_de_cuong),actual_validation_date:toISO(r.ngay_tham_dinh),
    actual_report_date:toISO(r.ngay_bao_cao),actual_vmp_date:toISO(r.ngay_vmp),
    scheduled_date:toISO(r.lich_td),
    rawSP,rawSV,rawSR,rawSVMP,
    sheet_sp:mapStatus(rawSP),sheet_sv:mapStatus(rawSV),sheet_sr:mapStatus(rawSR),sheet_svmp:mapStatus(rawSVMP)});
}
if(warnNonNum.length) console.log('⚠ Hàng có chữ trong cột số (VẪN đồng bộ):',warnNonNum);

const dbMap=new Map(); for(const r of dbRows) dbMap.set(r.validation_code||r.id,r);
const results=[]; let stats={insert:0,update:0,soft_delete:0,conflict:0,skip:0};

for(const [vc,sh] of sheetMap){
  const db=dbMap.get(vc);
  if(!db){
    results.push({json:{_op:'insert',
      id:vc,validation_code:vc,object_code:sh.object_code,
      validation_type:sh.validation_type,report_class:sh.report_class,
      owner_name:sh.owner_name,effort_days:sh.effort_days,criticality_score:sh.criticality_score,
      deadline_vmp:sh.deadline_vmp,deadline_protocol:sh.deadline_protocol,deadline_report:sh.deadline_report,
      actual_protocol_date:sh.actual_protocol_date,actual_validation_date:sh.actual_validation_date,
      actual_report_date:sh.actual_report_date,actual_vmp_date:sh.actual_vmp_date,
      scheduled_date:sh.scheduled_date,
      status_protocol:sh.sheet_sp,status_validation:sh.sheet_sv,status_report:sh.sheet_sr,status_vmp:sh.sheet_svmp,
      is_active:true,year:new Date().getFullYear()}});
    stats.insert++;
  } else {
    const patch={}; let changed=false;
    for(const f of ['object_code','validation_type','report_class','owner_name','effort_days','criticality_score','deadline_vmp','deadline_protocol','deadline_report']){
      if(String(sh[f]??'')!==String(db[f]??'')){patch[f]=sh[f];changed=true;}
    }
    const sflds=[
      {raw:'rawSP',s:'sheet_sp',d:'status_protocol',a:'actual_protocol_date'},
      {raw:'rawSV',s:'sheet_sv',d:'status_validation',a:'actual_validation_date'},
      {raw:'rawSR',s:'sheet_sr',d:'status_report',a:'actual_report_date'},
      {raw:'rawSVMP',s:'sheet_svmp',d:'status_vmp',a:'actual_vmp_date'}];
    for(const sf of sflds){
      if(sh[sf.raw]==='') continue;                 // S1-2: ô trống -> không đụng trạng thái
      if(sh[sf.s]!==db[sf.d]){
        if(db[sf.a]&&db[sf.d]==='completed'&&sh[sf.s]!=='completed'){
          results.push({json:{_op:'conflict',validation_code:vc,field:sf.d,db_val:db[sf.d],sheet_val:sh[sf.s]}}); stats.conflict++;
        } else { patch[sf.d]=sh[sf.s]; changed=true; }
      }
    }
    for(const af of ['actual_protocol_date','actual_validation_date','actual_report_date','actual_vmp_date','scheduled_date']){
      if(sh[af]&&String(sh[af])!==String(db[af]??'')){patch[af]=sh[af];changed=true;}
    }
    if(db.missing_from_sheet){patch.missing_from_sheet=false;patch.missing_since=null;changed=true;}
    if(changed){results.push({json:{_op:'update',validation_code:vc,...patch}});stats.update++;} else stats.skip++;
  }
}
for(const [vc,db] of dbMap){ if(!sheetMap.has(vc)&&db.is_active){results.push({json:{_op:'soft_delete',validation_code:vc}});stats.soft_delete++;} }
if(results.length===0) results.push({json:{_op:'noop'}});
results.push({json:{_op:'log',stats,codes_in_sheet:[...sheetCodes]}}); // S2-2
return results;

