// ============================================================
// BUILD OBJECTS UPSERT — sinh vmp_objects từ Google Sheet
// (BẮT BUỘC chạy trước khi INSERT vmp_plan_items vì object_code
//  có khoá ngoại REFERENCES vmp_objects(code))
// ============================================================
const rows = $('1. Read Sheet').all().map(i => i.json);
const s  = (v) => (v == null ? '' : String(v)).trim();
const lc = (v) => s(v).toLowerCase();
const esc = (v) => (v == null || v === '') ? 'NULL' : `'${String(v).replace(/'/g, "''")}'`;

function mapClass(x){ x = lc(x);
  if (/thiết bị|thiet bi|equipment|máy|may/.test(x)) return 'tb';
  if (/quy trình|quy trinh|process|sop|công đoạn|cong doan/.test(x)) return 'qt';
  if (/kho|warehouse|storage|bảo quản|bao quan/.test(x)) return 'kho';
  if (/hệ thống|he thong|phụ trợ|phu tro|hvac|utility|khí|khi|nước|nuoc|điều hòa|dieu hoa/.test(x)) return 'ht';
  if (/vận chuyển|van chuyen|transport|logistics|cold chain|chuỗi lạnh|chuoi lanh/.test(x)) return 'vc';
  return 'tb';
}
function mapDept(x){ x = lc(x);
  if (/xsx|sản xuất|san xuat|xưởng|xuong|production|\bsx\b/.test(x)) return 'sx';
  if (/cơ điện|co dien|mep|kỹ thuật|ky thuat|engineering|cđ|\bcd\b/.test(x)) return 'cd';
  if (/\bkho\b|warehouse/.test(x)) return 'kho';
  if (/\brd\b|r&d|nghiên cứu|nghien cuu|research|qc|kiểm nghiệm|kiem nghiem|lab/.test(x)) return 'qc';
  if (/\bqa\b|qlcl|đảm bảo|dam bao|quality|chất lượng|chat luong/.test(x)) return 'qa';
  return 'qa';
}
function critScore(v){ const n = parseInt(v, 10);
  if (isNaN(n)) return 'medium';
  if (n >= 7) return 'high';
  if (n >= 4) return 'medium';
  return 'low';
}

const seen = new Map();
for (const r of rows) {
  const code = s(r.ma); if (!code) continue;
  // bỏ dòng chú thích lẫn trong vùng dữ liệu (cột số chứa chữ)
if (!seen.has(code)) {
    const score = parseInt(r.diem_trong_yeu, 10);
    seen.set(code, {
      code, name: s(r.ten) || code,
      classification: mapClass(r.phan_loai),
      department: mapDept(r.bo_phan),
      area: s(r.khu_vuc) || '—', line: s(r.line) || '—',
      criticality_score: isNaN(score) ? null : score,
      criticality: critScore(r.diem_trong_yeu),
      frequency_months: parseInt(r.tan_suat, 10) || 12,
    });
  } else {
    // ô gộp: lấp dữ liệu thiếu từ dòng sau
    const o = seen.get(code);
    if ((!o.name || o.name === code) && s(r.ten)) o.name = s(r.ten);
    if (o.classification === 'tb' && s(r.phan_loai)) o.classification = mapClass(r.phan_loai);
    if (o.area === '—' && s(r.khu_vuc)) o.area = s(r.khu_vuc);
  }
}

const objs = [...seen.values()];
if (objs.length === 0) return [{ json: { query: 'SELECT 1' } }];

const vals = objs.map(o =>
  `(${esc(o.code)},${esc(o.name)},${esc(o.classification)},${esc(o.department)},${esc(o.area)},${esc(o.line)},` +
  `${o.criticality_score == null ? 'NULL' : o.criticality_score},${esc(o.criticality)}::criticality,${o.frequency_months})`
).join(',');

const query =
  `INSERT INTO vmp_objects (code,name,classification,department,area,line,criticality_score,criticality,frequency_months) ` +
  `VALUES ${vals} ` +
  `ON CONFLICT (code) DO UPDATE SET name=EXCLUDED.name, classification=EXCLUDED.classification, ` +
  `department=EXCLUDED.department, area=EXCLUDED.area, line=EXCLUDED.line, ` +
  `criticality_score=EXCLUDED.criticality_score, criticality=EXCLUDED.criticality, ` +
  `frequency_months=EXCLUDED.frequency_months, updated_at=NOW();`;

return [{ json: { query, _objects_count: objs.length } }];

// =====================================================================
//  WF-01 · Node Code MỚI: "1. Read Sheet"  (CHUẨN HÓA CỘT)
//  ---------------------------------------------------------------------
//  VẤN ĐỀ: Tab "6.Timeline VMP" có tiêu đề cột bằng TIẾNG VIỆT đầy đủ
//          ("Mã đối tượng", "ID thẩm định", "Trạng thái đề cương"...),
//          trong khi Diff Engine + Build Objects + frontend lại đọc theo
//          KHÓA NGẮN (ma, id, loai_td, tt_de_cuong, dl_vmp...).
//          → node Google Sheets trả về object có key tiếng Việt → r.ma,
//            r.id... đều undefined → MỌI dòng bị bỏ qua → KHÔNG có dữ liệu.
//
//  CÁCH DÙNG (mẹo không phải sửa Diff Engine/Build Objects):
//    1) Đổi tên node Google Sheets hiện tại "1. Read Sheet" → "1. Read Sheet (raw)"
//       và sửa Sheet name của nó thành: 6.Timeline VMP
//    2) Thêm node Code này, ĐẶT TÊN ĐÚNG: "1. Read Sheet"
//       (giữ nguyên tên cũ → mọi $('1. Read Sheet') ở Diff Engine/Build Objects
//        sẽ tự lấy dữ liệu ĐÃ chuẩn hóa, không cần sửa code các node đó).
//    3) Nối:  CONFIG → "1. Read Sheet (raw)" → "1. Read Sheet" (node này) → "0. Build Objects SQL"
//
//  Bảng ánh xạ Tiếng Việt → khóa ngắn nằm ở MAP bên dưới. Sheet đổi tiêu đề
//  thì chỉ sửa ở đây.
// =====================================================================

// Gộp xuống dòng/khoảng trắng thừa, bỏ phân biệt hoa thường → so khớp ổn định.
function norm(h) {
  return String(h == null ? '' : h).replace(/\s+/g, ' ').trim().toLowerCase();
}

// normalized(header tiếng Việt)  →  khóa ngắn pipeline cần
const MAP = {
  'stt': 'stt',
  'phân loại đối tượng': 'phan_loai',
  'loại thẩm định': 'loai_td',
  'mã đối tượng': 'ma',
  'tên đối tượng': 'ten',
  'bộ phận quản lý': 'bo_phan',
  'mã khu vực': 'khu_vuc',
  'line': 'line',
  'tình trạng': 'tinh_trang',
  'show': 'show',
  'thẩm định': 'td',
  'tần suất thẩm định (tháng)': 'tan_suat',
  'năm': 'nam',
  'id thẩm định': 'id',                                   // ← KHÓA NGHIỆP VỤ (validation_code)
  'qa phụ trách (qa nhập)': 'qa',
  'email (qa nhập)': 'email_qa',
  'nhân sự bộ phận khác (bộ phận khác nhập)': 'ns_khac',
  'email (bộ phận khác nhập)': 'email_khac',
  'deadline đề cương (t- 60 ngày)': 'dl_de_cuong',
  'thời gian thực tế hoàn thành đề cương': 'ngay_de_cuong',
  'trạng thái đề cương': 'tt_de_cuong',
  'deadline thẩm định thực tế (t-5-bc)': 'dl_tham_dinh',
  'bộ phận quản lý xếp lịch thẩm định (dd/mm/yyyy hh:mm:ss)': 'lich_td',
  'thời gian thực tế hoàn thành thẩm định thực tế': 'ngay_tham_dinh',
  'trạng thái thẩm định thực tế': 'tt_tham_dinh',
  'phân loại báo cáo': 'phan_loai_bc',
  'deadline báo cáo (t-5 ngày)': 'dl_bao_cao',
  'thời gian thực tế hoàn thành báo cáo': 'ngay_bao_cao',
  'trạng thái báo cáo': 'tt_bao_cao',
  'deadline vmp (t)': 'dl_vmp',
  'thời gian thực tế deadline vmp': 'ngay_vmp',
  'trạng thái vmp': 'tt_vmp',
  // --- 2 cột NÊN THÊM vào Sheet (xem khuyến nghị) — đã map sẵn ở đây ---
  'điểm trọng yếu': 'diem_trong_yeu',   // 1–9 → criticality_score / criticality
  'số ngày công': 'so_ngay_cong',       // → effort_days (ma trận khối lượng)
};

// Các cột rác do ghi ngược cũ tạo ra → BỎ, không đưa vào pipeline.
const IGNORE = new Set(['hasnewrows', 'count', 'debug_sheeta', 'debug_sheetb', 'id', '_attempts', '_outbox_id']);
// Lưu ý: 'id' ở đây là cột tự sinh (col37) — ta KHÔNG dùng nó; khóa nghiệp vụ lấy từ 'ID thẩm định'.

// Chuyển Date (nếu node trả về kiểu Date) → 'yyyy-mm-dd'.
function val(v) {
  if (v instanceof Date) {
    const y = v.getFullYear(), m = String(v.getMonth() + 1).padStart(2, '0'), d = String(v.getDate()).padStart(2, '0');
    return `${y}-${m}-${d}`;
  }
  return v;
}

const out = [];
const unmatched = new Set();
let skipped = 0;

for (const item of $input.all()) {
  const raw = item.json || {};
  const mapped = {};

  for (const [k, v] of Object.entries(raw)) {
    const nk = norm(k);
    if (IGNORE.has(nk)) continue;
    const target = MAP[nk];
    if (target) {
      mapped[target] = val(v);
    } else if (nk) {
      unmatched.add(k);          // ghi log để dễ soi nếu Sheet đổi tiêu đề
    }
  }

  // Đồng nhất khóa nghiệp vụ cho Diff Engine (đọc cả r.id lẫn r.validation_code).
  if (mapped.id) mapped.validation_code = mapped.id;

  // QUY TẮC: chỉ lấy dòng CÓ "ID thẩm định". Dòng để trống ID → BỎ QUA (không đồng bộ,
  // không hiển thị trên web). Nhờ vậy mỗi hạng mục luôn có 1 khóa duy nhất, không trùng.
  const idVal = mapped.id == null ? '' : String(mapped.id).trim();
  if (!idVal) { skipped++; continue; }

  out.push({ json: mapped });
}

// In cảnh báo (xem ở tab Output/Logs của node) nếu có tiêu đề chưa map.
if (unmatched.size) console.log('⚠ Cột chưa ánh xạ (bỏ qua):', Array.from(unmatched));
console.log(`✓ Chuẩn hóa ${out.length} dòng có ID thẩm định · bỏ ${skipped} dòng trống ID.`);

return out;

// ====== SỬA 1 GIÁ TRỊ DUY NHẤT Ở ĐÂY ======
// Lấy ID giữa /d/ và /edit trong URL Google Sheet.
return [{ json: {
  GOOGLE_SHEET_ID: "1MPG6YbR6m-YrENqb8u7uS3O8RUYk7GCYuzQRbShtqP8",
} }];

